INSERT INTO `priority` VALUES (1,1,'src/main/java/com/ssafy/pageon/challenge/entity/Challenge.java 파일에서 추가된 새로운 비즈니스 로직이 기존의 기능과 어떻게 상호작용하는지, 특히 엣지 케이스와 예외 처리 로직이 적절한지 확인해야 합니다.','HIGH','Challenge Entity의 비즈니스 로직 검토'),(2,1,'여러 Challenge 관련 엔티티가 추가되면서 데이터베이스 스키마에 영향을 미칠 수 있습니다. src/main/java/com/ssafy/pageon/challenge/entity/ChallengeParticipation.java와 src/main/java/com/ssafy/pageon/challenge/entity/ChallengeType.java의 관계 및 제약 조건 확인이 필요합니다.','HIGH','데이터베이스 무결성 및 관계 검증'),(3,1,'다수의 Challenge 관련 엔티티가 새로 추가되었으므로, src/main/java/com/ssafy/pageon/challenge/entity/HeadcountLimit.java와 src/main/java/com/ssafy/pageon/challenge/entity/Period.java의 일관성 및 데이터의 유효성을 검토해야 합니다.','MEDIUM','Challenge 관련 엔티티의 일관성 검토'),(4,2,'src/main/java/com/ssafy/pageon/auth/dto/KakaoToken.java 파일에서 신규 추가된 보안 관련 코드가 사용자의 인증 토큰을 생성하거나 처리하는 로직으로 추정됩니다. 이 로직은 외부 공격이나 허가되지 않은 접근에 취약할 수 있으므로, 토큰 생성 및 검증 과정에서 발생할 수 있는 잠재적 보안 결함을 확인해야 합니다.','CRITICAL','KakaoToken 클래스의 보안 토큰 처리 검토'),(5,2,'src/main/java/com/ssafy/pageon/auth/dto/KakaoUserInfo.java에서 추가된 사용자 정보 처리 로직이 실제 사용자 데이터를 어떻게 처리하는지를 명확히 검토해야 합니다. 사용자의 민감한 정보가 포함된 경우, 데이터 보호 및 프라이버시 관련 문제가 발생할 수 있으므로 해당 로직의 안전성을 검토하고 모든 경우에 올바르게 동작하는지 확인해야 합니다.','CRITICAL','KakaoUserInfo 클래스의 사용자 정보 처리 안전성 검토'),(6,2,'src/main/java/com/ssafy/pageon/auth/dto/LoginResponse.java 파일이 새로운 로그인 응답 구조를 정의하고 있습니다. 이 구조가 클라이언트와 서버 간의 상호작용에서 취약점을 유발하지 않도록, 리스폰스의 형식 및 내용이 의도한 대로 제공되는지, 또 전송되는 정보가 적절하게 보호되는지 검토해야 합니다.','CRITICAL','LoginResponse 클래스의 인증 응답 구조 검토'),(7,3,'src/main/java/com/ssafy/pageon/feed/entity/FavoriiteBook.java, Feed.java, Magazine.java, Story.java 파일에서 새로운 엔티티가 추가되었습니다. 이로 인해 데이터베이스 스키마의 무결성이 영향을 받을 수 있으며, 적절한 데이터 마이그레이션과 관계 설정이 필요합니다. 데이터베이스 내에서의 하위 호환성 문제를 확인해야 합니다.','HIGH','엔티티 추가에 따른 데이터베이스 무결성 검토'),(8,3,'src/main/java/com/ssafy/pageon/feed/entity/Feed.java에서 주요 로직 수정이 이루어져 있습니다. Feed 엔티티가 추가됨에 따라 비즈니스 로직 및 데이터를 처리하는 방식이 변경될 가능성이 있으므로, 특정 비즈니스 프로세스에서의 로직 흐름이 정상적으로 작동하는지 테스트해야 합니다.','HIGH','Feed 엔티티의 구조적 변경'),(9,3,'새로 추가된 FavoriiteBook, Feed, Magazine, Story 엔티티에 대한 적절한 API 엔드포인트가 설정되었는지 검토해야 합니다. API에 대한 문서화가 누락되면 사용자가 새로운 데이터 모델을 활용할 수 없으므로, API 문서와 단위 테스트를 확인하는 것이 중요합니다.','MEDIUM','새로운 데이터 모델의 API 반영'),(10,4,'src/main/java/com/ssafy/pageon/auth/event/ProfileImageUploadEventHandler.java 파일에서 사용자 프로필 이미지 업로드 시 인증 관련 로직이 추가되었습니다. 이 로직이 공격에 대해 안전한지, 예외 처리가 적절히 되어 있는지 확인해야 합니다.','CRITICAL','토큰 및 인증 처리 로직의 안전성 확인 필요'),(11,4,'src/main/java/com/ssafy/pageon/auth/event/RegisteredEvent.java 파일에서 추가된 인증 이벤트로 인해 데이터 검증 및 처리 로직의 신뢰성이 필요합니다. 유효하지 않은 데이터가 시스템에 들어오는 경우를 포함해 어떤 검증이 이루어지는지 점검해야 합니다.','HIGH','신규 이벤트 클래스의 데이터 검증 로직 검토'),(12,4,'src/main/java/com/ssafy/pageon/auth/event/ProfileImageUploadEventHandler.java 파일 내에서 이미지 업로드 처리 로직이 추가되었습니다. 업로드된 이미지의 크기, 형식 등에 대한 제약 조건 확인 및 이에 따른 에러 처리 로직이 명확한지 검토해야 합니다.','MEDIUM','프로필 이미지 업로드와 관련된 비즈니스 로직 확인'),(13,5,'FavoritesBookService, FeedService, MagazineService, StoryService 파일에서 보안 관련 사항이 업데이트되었습니다. 특히 사용자 인증 및 데이터 접근에 대한 권한 부여 로직이 변경되었을 가능성이 높습니다. 각 서비스 파일에서 JWT 검증 및 권한 체크를 점검해야 합니다.','CRITICAL','보안 관련 로직 검토 필요'),(14,5,'FeedService, FavoriteBookService 파일의 비즈니스 로직이 변경되었습니다. 특히 데이터 처리 흐름이나 서비스 간의 상호작용 방식이 바뀌었을 수 있습니다. 특정 조건에서의 비즈니스 규칙이 어떻게 적용되는지를 파악하고, 엣지 케이스를 추가로 테스트해야 합니다.','HIGH','비즈니스 로직 변경 확인'),(15,5,'FeedService 및 MagazineService에서 데이터베이스와의 상호작용이 새로 추가되었습니다. 데이터 스키마와의 호환성 문제가 발생할 수 있으므로, 어떤 데이터를 저장하고 조회하는지를 확인하고 관련 스키마 변경이 필요한지 검토해야 합니다.','HIGH','데이터베이스 상호작용 검토'),(16,6,'src/main/java/com/ssafy/pageon/auth/jwt/JwtInterceptor.java 및 JwtArgumentResolver.java에서 JWT 토큰 처리 로직이 추가되었습니다. 권한 부여 및 인증 흐름에서의 보안 취약점이 발생할 수 있는지 확인해야 합니다. 특히, 토큰 검증 및 오류 처리 로직을 검토하여 비정상적인 요청에 대한 처리 방안이 적절한지 점검하십시오.','CRITICAL','JWT 토큰 처리 로직에 대한 보안 검토'),(17,6,'src/main/java/com/ssafy/pageon/auth/jwt/TokenBlacklistRepository.java에서 블랙리스트 처리 로직이 추가되었습니다. 데이터베이스의 스키마 변경이나 쿼리가 올바르게 작성되었는지, 기존 데이터와의 호환성에 문제는 없는지를 점검해야 합니다. 블랙리스트된 토큰의 기록 및 관리 방식이 적절한지 검토하십시오.','HIGH','TokenBlacklistRepository의 데이터베이스 연동 검토'),(18,6,'src/main/java/com/ssafy/pageon/auth/jwt/JwtTokenProvider.java에서 JWT 생성 및 검증 로직이 구현되었습니다. 비즈니스 로직의 변경으로 인해 특정 조건에서의 토큰 생성 및 검증의 엣지 케이스가 어떻게 처리되는지를 확인해야 합니다. 특히, 만료된 토큰이나 잘못된 토큰이 주어졌을 때의 처리 로직에 주의해야 합니다.','HIGH','JWT 환경설정 관련 비즈니스 로직 검토'),(19,7,'이 PR에서는 JWT 예외 처리와 관련된 여러 클래스가 추가되었습니다. 특히, 사용자 인증과 관련된 AccessDeniedException, ExpiredTokenException, InvalidTokenException의 구현이 포함되어 있습니다. 이러한 보안 관련 로직의 변경은 인증 및 권한 상승의 취약점을 초래할 수 있으므로, 충분한 테스트 및 검토가 필요합니다.','CRITICAL','JWT 관련 보안 예외 처리 클래스 추가'),(20,7,'JwtErrorCode 클래스가 추가되어 JWT 처리 시 발생할 수 있는 다양한 오류의 코드가 정의되었습니다. 이 오류 코드들이 적절하게 매핑되어 있는지, 그리고 이를 호출하는 기존 시스템과의 호환성 문제가 없는지 면밀히 검토해야 합니다.','HIGH','JWT 오류 코드 클래스 구현'),(21,7,'예외 처리에 대한 비즈니스 로직이 여러 클래스에서 구현되었습니다. 각각의 예외가 실제 시스템에서 어떻게 사용되는지에 대한 이해가 필요하며, 새로운 예외 처리 로직이 기존 로직과 충돌하지 않는지 검토해야 합니다.','MEDIUM','다양한 JWT 예외 클래스 추가에 따른 비즈니스 로직 영향'),(22,8,'src/main/java/com/ssafy/pageon/challenge/repository/ChallengeParticipationRepository.java 파일에서 새로운 레포지토리가 추가되었습니다. 이 변경이 데이터 무결성과 기존 데이터베이스 스키마에 미치는 영향을 확인해야 하며, 스키마 변경으로 인한 하위 호환성 문제를 철저히 검토해야 합니다.','HIGH','ChallengeParticipationRepository와 관련된 데이터베이스 변경 검토'),(23,8,'src/main/java/com/ssafy/pageon/challenge/repository/ChallengeRepositor.java 파일이 새로 추가되었습니다. 이 레포지토리의 메서드들이 비즈니스 로직과 어떻게 연결되는지, 특정 쿼리에서 어떤 동작을 하는지를 면밀히 검토해야 하며, 성능 문제나 데이터 처리 오류 가능성을 고려해야 합니다.','HIGH','ChallengeRepositor 레포지토리 검토'),(24,8,'src/main/java/com/ssafy/pageon/challenge/repository/ChallengeVerificationRepository.java 파일에서 새로운 레포지토리가 추가되었습니다. 이 레포지토리의 사용처 및 초기화 부분을 확인하여, 애플리케이션에서 예상되는 데이터 흐름과 통합이 제대로 이루어지고 있는지 검토해야 합니다.','MEDIUM','ChallengeVerificationRepository의 초기화 및 사용 검토'),(25,10,'src/main/java/com/ssafy/pageon/auth/exception/AuthErrorCode.java 파일에서 새로운 인증 오류 코드가 추가되었으며, 이로 인해 인증 관련 로직의 보안성에 영향을 미칠 수 있습니다. 오류 코드가 올바르게 처리되고 있는지, 예외 발생 시 민감한 정보가 노출되지 않는지를 확인해야 합니다.','CRITICAL','새로운 인증 오류 코드 추가로 인한 보안 영향 분석'),(26,10,'src/main/java/com/ssafy/pageon/auth/exception/UserInfoNotFoundException.java 파일에서 사용자 정보가 발견되지 않을 때의 예외 처리 로직이 추가되었습니다. 이 로직이 기존 시스템과 호환되는지, 적절한 예외 메시지를 반환하는지 확인하며, 로깅 및 모니터링이 적절하게 설정되어 있는지도 검토해야 합니다.','CRITICAL','사용자 정보 미발견 예외 처리 로직 검토'),(27,10,'이번 PR에서 추가된 예외 로직들이 기존의 오류 처리 시스템과 일관되게 설계되었는지에 대한 검토가 필요합니다. 새로운 오류 코드와 예외 처리 방식이 기존의 정책과 충돌하지 않는지를 확인하고, 다양한 예외 상황에 대해 테스트 커버리지가 충분한지 점검해야 합니다.','MEDIUM','오류 처리 시스템의 일관성 검토'),(28,12,'src/main/java/com/ssafy/pageon/feed/controller/FavoriteBookController.java, FeedController.java, MagazineController.java 파일의 추가로 비즈니스 로직이 포함되어 있습니다. 이들 컨트롤러가 어떻게 작동하는지, 특히 데이터 흐름과 상태 변화가 기존 비즈니스 로직과 충돌하지 않는지 체크해야 합니다. 엣지 케이스로는 유효하지 않은 입력에 대한 처리, 컨트롤러 간의 상호작용을 검토해야 합니다.','HIGH','새로운 피드 관련 컨트롤러 추가로 인한 비즈니스 로직 변화'),(29,12,'새롭게 추가된 Controller들에서 데이터베이스와의 상호작용이 포함되어 있습니다. 특히, FeedController에서의 데이터 삽입 및 조회 로직이 기존 DB 스키마와 호환성이 있는지, 데이터 무결성을 해치지 않는지 확인해야 합니다.','HIGH','데이터베이스와 연관된 새로운 API 엔드포인트'),(30,12,'src/main/java/com/ssafy/pageon/feed/controller/StoryController.java 파일에서는 테스트 관련 코드와 비즈니스 로직이 포함되어 있습니다. 기존 테스트 케이스가 새로운 로직을 적절하게 다루고 있는지 확인하고, 새로운 로직이 예상된 대로 작동하는지 검토해야 합니다.','MEDIUM','StoryController의 테스트 및 비즈니스 로직 포함'),(31,13,'src/main/java/com/ssafy/pageon/auth/service/KakaoApiClient.java와 src/main/java/com/ssafy/pageon/auth/service/KakaoAuthService.java 파일에서 보안 관련 로직이 추가되었습니다. JWT 생성 및 검증, 사용자 인증을 포함한 인증 관련 로직이 정확하게 구현되었는지, 예외 처리 및 토큰 유효성 검증이 제대로 이루어지는지를 철저히 검토해야 합니다.','CRITICAL','KakaoApiClient와 KakaoAuthService의 보안 관련 로직 검증'),(32,13,'KakaoApiClient.java 파일이 새로 추가되면서 카카오 API와의 통신 방식이 정의되었습니다. 해당 API의 응답 처리 로직 및 예외 처리가 비즈니스 로직 흐름에 미치는 영향을 검토해야 하며, 관련 API 문서와의 일관성을 유지하고 있는지를 확인해야 합니다.','HIGH','KakaoApiClient의 비즈니스 로직 및 API 변경 점 확인'),(33,13,'KakaoAuthService.java에서 구성 설정 관련 코드가 추가되었습니다. 보안 설정이 적절하게 구현되었는지, 인증 로직 간의 의존성 관리가 잘 되었는지를 확인해야 하며, 추가된 설정에 의한 영향도를 평가해야 합니다.','MEDIUM','KakaoAuthService의 구성 및 보안 로직 점검'),(34,14,'src/main/java/com/ssafy/pageon/challenge/repository/ChallengeParticipationRepository.java 파일에서 새로운 레포지토리가 추가되었습니다. 이 변경이 데이터 무결성과 기존 데이터베이스 스키마에 미치는 영향을 확인해야 하며, 스키마 변경으로 인한 하위 호환성 문제를 철저히 검토해야 합니다.','HIGH','ChallengeParticipationRepository와 관련된 데이터베이스 변경 검토'),(35,14,'src/main/java/com/ssafy/pageon/challenge/repository/ChallengeRepositor.java 파일이 새로 추가되었습니다. 이 레포지토리의 메서드들이 비즈니스 로직과 어떻게 연결되는지, 특정 쿼리에서 어떤 동작을 하는지를 면밀히 검토해야 하며, 성능 문제나 데이터 처리 오류 가능성을 고려해야 합니다.','HIGH','ChallengeRepositor 레포지토리 검토'),(36,14,'src/main/java/com/ssafy/pageon/challenge/repository/ChallengeVerificationRepository.java 파일에서 새로운 레포지토리가 추가되었습니다. 이 레포지토리의 사용처 및 초기화 부분을 확인하여, 애플리케이션에서 예상되는 데이터 흐름과 통합이 제대로 이루어지고 있는지 검토해야 합니다.','MEDIUM','ChallengeVerificationRepository의 초기화 및 사용 검토'),(37,15,'src/main/java/com/ssafy/pageon/auth/token/AuthToken.java 파일에서 새로운 인증 토큰 관련 로직이 추가되었습니다. 이 파일의 변경 사항이 인증 및 권한 부여와 어떻게 연관되는지 확인해야 하며, 특히 토큰의 생성을 안전하게 처리하고 있는지 점검해야 합니다.','CRITICAL','AuthToken 클래스 보안 검토'),(38,15,'src/main/java/com/ssafy/pageon/auth/token/AuthTokenGenerator.java 파일에서 새롭게 추가된 토큰 생성 로직이 있습니다. 이 로직이 난독화 또는 변조에 안전한지를 확인하고, 토큰의 유효성 및 만료 시간 설정 역시 올바른지 검토해야 합니다.','CRITICAL','AuthTokenGenerator 클래스의 토큰 생성 로직 검증'),(39,15,'위의 두 파일에서 추가된 인증 토큰 로직에 대해 충분한 테스트 케이스가 존재하는지 여부를 확인해야 합니다. 특히 비정상적인 입력값이나 경계 조건에서의 반응을 검증하는 테스트가 필요합니다.','HIGH','토큰 관련 테스트 케이스 확인'),(40,16,'피드 레파지터리 신규 구현 (FavoriteBookRepository, FeedRepository, MagazineRepository, StoryRepository)으로 인해 데이터베이스와의 상호작용 방식이 변경되었습니다. 이로 인해 데이터 무결성 및 쿼리 성능에 영향을 미칠 수 있으므로, 적절한 데이터 검증 로직과 성능 테스트가 필요합니다.','HIGH','피드 관련 레파지터리 추가에 따른 데이터 무결성 검토'),(41,16,'피드 레파지터리들이 추가됨에 따라 기존 API와의 연동 여부와 각 레파지터리에서 제공해야 하는 기능이 API 스펙에 명확하게 반영되어야 합니다. API 문서화 및 하위 호환성 테스트가 필요합니다.','HIGH','신규 레파지터리의 API 연동 확인 필요'),(42,16,'여러 피드 레파지터리가 추가됨에 따라 이들 간의 관계 및 의존성 관리가 중요해졌습니다. 각 레파지터리 간의 데이터 관계와 관련된 로직이 필요한 경우, 이를 명확히 문서화하고 중복되는 로직이 없는지 확인해야 합니다.','MEDIUM','피드 레파지터리 간의 관계 및 의존성 검토'),(43,17,'KakaoAuthController.java 파일에서 보안 관련 로직이 새로 추가되었습니다. 특히, 사용자의 인증 정보가 어떤 방식으로 처리되는지, 토큰 생성 및 검증 로직에 취약점이 없는지 확인해야 합니다.','CRITICAL','KakaoAuthController의 보안 인증 로직 검토'),(44,17,'KakaoAuthController.java에서 비즈니스 로직이 포함되어 있으며, 사용자의 인증 요청 처리 흐름이 어떻게 변경되었는지 상세히 검토해야 합니다. 특히, 특정 조건에서의 에러 핸들링 및 응답 코드 확인이 필요합니다.','HIGH','비즈니스 로직 변경 검토'),(45,17,'KakaoAuthController.java의 변화가 API 명세 및 데이터베이스 연동에 미치는 영향을 검토해야 합니다. 새로 추가된 엔드포인트가 기존의 API와 어떻게 호환되는지, 데이터 저장 및 조회가 올바르게 이루어지는지 점검할 필요가 있습니다.','HIGH','API 명세 및 데이터베이스 연동 확인'),(46,18,'src/main/java/com/ssafy/pageon/feed/mapper/FeedMapper.java 파일에 비즈니스 로직 관련 코드가 추가되었습니다. 피드 매핑 로직의 정확성을 검증하기 위해 다양한 입력값과 엣지 케이스에 대한 테스트가 필요합니다. 특히 비어 있는 입력이나 예상치 못한 형식의 데이터 처리가 적절히 이루어지는지 확인해야 합니다.','MEDIUM','피드 매퍼의 비즈니스 로직 리뷰'),(47,18,'FeedMapper.java에 구현된 비즈니스 로직에 대한 테스트 코드가 포함되어 있습니다. 해당 테스트가 실제 비즈니스 로직을 충분히 검증하고 있는지, 모든 주요 경로를 테스트하고 있는지 점검할 필요가 있습니다. 특히 테스트의 커버리지가 얼마나 되는지 확인해야 합니다.','MEDIUM','테스트 코드 관련 검토'),(48,18,'대규모 변경은 아니지만, 새로운 매퍼 로직을 추가함에 따라 구조적으로 기존의 코드베이스에 통합될 때 일관성을 유지해야 합니다. FeedMapper.java가 다른 피드 관련 모듈과 어떻게 연결되며, 실행 흐름에서의 영향력을 고려해야 합니다.','MEDIUM','전체적인 아키텍처 일관성 검토'),(49,19,'src/main/java/com/ssafy/pageon/challenge/controller/ChallengeController.java 파일에서 새로운 비즈니스 로직이 추가되었습니다. 데이터베이스와의 인터페이스 변경이 포함되어 있어, 철저한 검토가 필요합니다. 특히 데이터 일관성 및 사용자 요구사항에 대한 검증이 필요합니다.','HIGH','ChallengeController 파일의 비즈니스 로직 및 데이터베이스 영향 분석'),(50,19,'src/main/java/com/ssafy/pageon/challenge/controller/ChallengeParticipationController.java 파일에서도 비즈니스 로직이 추가되었습니다. 기존 데이터베이스 구조와의 호환성 및 API 응답 형식에 대한 검토가 중요하며, 테스트 케이스 작성이 필요합니다.','HIGH','ChallengeParticipationController에서의 데이터베이스 및 비즈니스 로직 통합 분석'),(51,19,'src/main/java/com/ssafy/pageon/challenge/controller/ChallengeVerificationController.java 파일의 추가된 로직이 기존 시스템에 부정적인 영향을 미치지 않는지 확인할 필요가 있습니다. 인증 및 검증 로직의 엣지 케이스를 충분히 다뤄야 합니다.','HIGH','ChallengeVerificationController의 비즈니스 로직 검증 필요'),(52,20,'src/main/java/com/ssafy/pageon/auth/jwt/JwtTokenProvider.java 파일에서 토큰 생성 로직이 변경되었습니다. 이 변경이 보안에 미치는 영향을 검토해야 하며, 특히 토큰의 유효성 검사 및 만료 처리 로직이 바뀌었는지를 확인해주세요.','CRITICAL','토큰 생성 로직 변경의 보안 검토'),(53,20,'해당 변경으로 인해 토큰 생성 과정의 유효성에 영향을 줄 수 있으므로 관련된 테스트 코드가 충실히 추가되었는지 확인해야 합니다. 기존의 엣지 케이스가 잘 처리되는지 살펴보세요.','MEDIUM','중간규모 변경에 따른 테스트 추가 필요성'),(54,20,'JwtTokenProvider의 인터페이스 변경 시 다른 모듈에서의 의존성 영향을 평가할 필요가 있습니다. 특히, 이 모듈을 사용하는 다른 서비스나 이벤트 리스너에서의 호환성을 점검해야 합니다.','MEDIUM','TokenProvider 인터페이스 변경 테스트 진행'),(55,21,'src/main/java/com/ssafy/pageon/auth/jwt/JwtTokenProvider.java 파일에서 JWT 토큰 생성 방식에 변경이 있습니다. 이 로직은 보안 인증과 관련이 깊으므로, 엣지 케이스로는 유효하지 않은 사용자 정보를 처리하는 경우와 만료된 토큰 사용 시의 예외 처리를 확인해야 합니다.','CRITICAL','JWT 토큰 생성 로직 수정'),(56,21,'토큰 생성에 대한 변경은 전체 인증 시스템에 영향을 미칠 수 있습니다. 기존의 인증 흐름과의 호환성을 위해 사용되는 모든 경로에서 엑세스 토큰이 잘 처리되고 있는지 확인할 필요가 있습니다.','HIGH','엑세스 토큰 관련 보안 점검'),(57,21,'토큰 생성 과정에서 발생할 수 있는 오류에 대한 처리 방법이 변경되지 않았다면, 이로 인해 인증 실패 시 적절한 오류 메시지를 사용자에게 제공하지 못할 수 있습니다. 관련된 부분에 대한 검토가 필요합니다.','MEDIUM','추가적인 에러 처리 및 로그'),(58,22,'src/main/java/com/ssafy/pageon/challenge/dto/AuthorResponse.java와 src/main/java/com/ssafy/pageon/challenge/dto/ChallengeVerificationResponse.java 파일이 새로 추가되었으며, 이들 파일은 보안 관련 정보를 다룹니다. 특히, 적절한 인증 및 권한 부여가 적용되었는지 검토해야 합니다.','CRITICAL','보안 관련 DTO 추가에 대한 위험 분석'),(59,22,'src/main/java/com/ssafy/pageon/challenge/dto/ChallengeRequest.java와 src/main/java/com/ssafy/pageon/challenge/dto/ChallengeResponse.java 파일이 비즈니스 로직 및 데이터 관련 변경을 포함하고 있습니다. 이들 파일의 변경으로 인한 데이터 무결성과 하위 호환성 문제가 발생할 수 있으므로, 해당 로직의 정확성을 검토할 필요가 있습니다.','HIGH','비즈니스 로직 및 데이터베이스 관련 변경 분석'),(60,22,'다수의 일반적인 코드 변경이 포함된 파일들이 추가되었습니다. 이는 시스템 전체적으로 코드 품질에 영향을 미칠 수 있으므로, 변경된 각 DTO의 구조와 사용 방식이 일관성이 있는지 확인해야 합니다.','MEDIUM','일반적인 코드 변경 및 자원 관리 분석'),(61,23,'src/main/java/com/ssafy/pageon/feed/exception/feed/DeleteNotAuthorizedException.java 파일에서 권한 부여 관련 예외 처리 로직이 추가되었습니다. 이 로직이 예상대로 작동하는지, 혹은 악용될 수 있는 여지가 없는지 확인해야 합니다.','CRITICAL','보안 관련 예외 처리 변경'),(62,23,'src/main/java/com/ssafy/pageon/feed/exception/feed/FavoriteBookRequiredBookException.java 파일에서 비즈니스 로직 오류 처리를 위한 새로운 예외가 도입되었습니다. 이 예외가 어떤 상황에서 발생하며 적절하게 처리되는지 검토해야 합니다.','HIGH','비즈니스 로직 관련 예외 처리 추가'),(63,23,'여러 개의 DTO 파일(src/main/java/com/ssafy/pageon/feed/dto/*)이 추가되었습니다. 이로 인해 기존 API의 데이터 흐름과 호환성 문제를 검토해야 하며, 특히 어떤 스키마 변화가 있는지 확인해야 합니다.','MEDIUM','DTO 구현에 따른 API 변경 검토'),(64,30,'src/main/java/com/ssafy/pageon/challenge/controller/ChallengeController.java 파일에서 비즈니스 로직이 수정되었습니다. 이 변경이 기존 기능에 미치는 영향을 분석하고, 엣지 케이스를 테스트해야 합니다.','HIGH','비즈니스 로직 변경 확인 필요'),(65,30,'src/main/java/com/ssafy/pageon/challenge/entity/ChallengeParticipation.java 및 src/main/java/com/ssafy/pageon/challenge/repository/ChallengeRepositor.java 파일에서 데이터베이스 관련 변경사항이 있습니다. 이들 변경이 데이터 무결성이나 하위 호환성에 미치는 영향을 검토해야 합니다.','HIGH','데이터베이스 연관 로직 검토 필요'),(66,30,'src/main/java/com/ssafy/pageon/challenge/dto/AuthorResponse.java에서 일반적인 코드 변경이 있었으며, 이 변경이 오류 해결에 기여했는지 확인해야 합니다. 예외 처리에 중점을 두고 검토해야 합니다.','MEDIUM','예외 처리 및 오류 해결 여부 점검'),(67,31,'src/main/java/com/ssafy/pageon/auth/jwt/exception 패키지에서 여러 보안 관련 예외 처리 파일들이 추가되었습니다. 이 파일들은 JWT 관련 토큰 검증 및 오류 처리를 포함하고 있으며, 애플리케이션의 인증 체계에 직접적인 영향을 미칩니다. 특히 InvalidTokenException 및 SignatureValidationFailedException과 같은 예외가 적절히 처리되지 않을 경우 보안 취약점으로 이어질 수 있으므로, 이들 파일에서 처리되는 로직을 면밀히 검토해야 합니다.','CRITICAL','보안 관련 예외 처리 파일 추가'),(68,31,'userInfoNotFoundException.java 파일이 추가되었습니다. 사용자의 정보를 찾지 못했을 경우 발생하는 예외로, 이 예외가 시스템의 비즈니스 로직과 어떻게 연결되는지 확인해야 합니다. 적절한 예외 처리가 없으면 사용자 경험에 부정적인 영향을 미칠 수 있습니다. 또한 이 예외와 연관된 호출 흐름 및 로직 검토가 필요합니다.','HIGH','사용자 정보 관련 예외 처리 추가'),(69,31,'src/main/java/com/ssafy/pageon/challenge/entity/ChallengeVerification 및 ChallengeParticipationRepository.java와 같은 데이터베이스 관련 파일들이 변경되었습니다. 데이터베이스 스키마와 API의 일관성을 검토해야 하며, 새로운 변경이 적용되었을 때 기존 데이터와의 호환성을 확인해야 합니다.','MEDIUM','Database 관련 엔티티 및 리포지토리 변경'),(70,32,'src/main/java/com/ssafy/pageon/feed/entity/Likes.java 파일이 추가되었습니다. 이는 데이터베이스 스키마에 영향을 미칠 수 있으며, 기존 데이터와의 호환성 검토가 필요합니다. 또한, Likes 엔티티의 필드와 제약 조건이 잘 정의되었는지 확인해야 합니다.','HIGH','Likes 엔티티 추가에 따른 데이터베이스 변경 검토'),(71,32,'src/main/java/com/ssafy/pageon/feed/service/LikesService.java 파일에서 비즈니스 로직이 추가되었습니다. Likes 엔티티를 다루는 로직의 유효성 검증, 에러 처리 및 트랜잭션 관리가 적절히 이루어졌는지 확인해야 하며, 특히 엣지 케이스에 대한 테스트를 검토해야 합니다.','HIGH','LikesService의 비즈니스 로직 변경 확인'),(72,32,'새로운 LikesService와 Likes 엔티티와 관련된 테스트 코드는 추가되지 않았습니다. 실제 서비스 통합이 문제없이 작동하는지 확인하기 위해 단위 테스트 및 통합 테스트 작성이 필요합니다.','MEDIUM','서비스 및 컨트롤러 통합 테스트 필요성 검토');
