--
-- Table structure for table `pull_request`
--

DROP TABLE IF EXISTS `pull_request`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pull_request` (
  `approve_cnt` int NOT NULL,
  `changed_files_cnt` int DEFAULT NULL,
  `comment_cnt` int DEFAULT NULL,
  `commit_cnt` int DEFAULT NULL,
  `github_pr_number` int DEFAULT NULL,
  `mergeable` bit(1) NOT NULL,
  `merged` bit(1) NOT NULL,
  `review_comment_cnt` int DEFAULT NULL,
  `created_at` datetime(6) NOT NULL,
  `github_created_at` datetime(6) DEFAULT NULL,
  `github_id` bigint DEFAULT NULL,
  `github_updated_at` datetime(6) DEFAULT NULL,
  `id` bigint NOT NULL AUTO_INCREMENT,
  `modified_at` datetime(6) NOT NULL,
  `repo_id` bigint DEFAULT NULL,
  `user_id` bigint DEFAULT NULL,
  `base` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `body` text COLLATE utf8mb4_unicode_ci,
  `commit_sha` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `diff_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `head` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `html_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `issue_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `patch_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `summary` text COLLATE utf8mb4_unicode_ci,
  `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `state` enum('CLOSED','MERGED','OPEN') COLLATE utf8mb4_unicode_ci NOT NULL,
  PRIMARY KEY (`id`),
  KEY `FKm3qh1fx6ay5vlfcpdl36rq1o1` (`user_id`),
  KEY `FKj3ihkmy34wxvwetsqiifnlk8m` (`repo_id`),
  CONSTRAINT `FKj3ihkmy34wxvwetsqiifnlk8m` FOREIGN KEY (`repo_id`) REFERENCES `repository` (`id`) ON DELETE CASCADE,
  CONSTRAINT `FKm3qh1fx6ay5vlfcpdl36rq1o1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=33 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

