  `start_side` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `UK1a8ejyd9dvqop4wxxpjmvl5r1` (`github_id`),
  KEY `FKmh0o5lpwf7uf1b318udd89vh4` (`parent_comment_id`),
