  KEY `FKpgr2q1cxlrcy0i08wjp10lke3` (`user_id`),
  CONSTRAINT `FK9j7pkcpuestrwjre1a1902biu` FOREIGN KEY (`review_id`) REFERENCES `review` (`id`) ON DELETE CASCADE,
  CONSTRAINT `FKmh0o5lpwf7uf1b318udd89vh4` FOREIGN KEY (`parent_comment_id`) REFERENCES `review_comment` (`id`),
  CONSTRAINT `FKpgr2q1cxlrcy0i08wjp10lke3` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=38 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
